code = """import pandas as pd
import json
from scipy.stats import chi2_contingency

# Load clinical data for female BRCA patients with known histological types
fem_brca_clinical_df_path = locals()['var_function-call-11083837588506990406']
with open(fem_brca_clinical_df_path, 'r') as f:
    fem_brca_clinical_data = json.load(f)
fem_brca_clinical_df = pd.DataFrame(fem_brca_clinical_data)

# Load CDH1 mutation data
cdh1_mutation_data = locals()['var_function-call-9852185754434013128']
cdh1_mutated_patients = {patient['ParticipantBarcode'] for patient in cdh1_mutation_data}

# Mark patients with CDH1 mutations in the clinical dataframe
fem_brca_clinical_df['has_cdh1_mutation'] = fem_brca_clinical_df['patient_id'].apply(lambda x: 1 if x in cdh1_mutated_patients else 0)

# Create contingency table
contingency_table = pd.crosstab(fem_brca_clinical_df['histological_type'], fem_brca_clinical_df['has_cdh1_mutation'])

# Exclude categories with marginal totals less than or equal to 10
contingency_table_filtered = contingency_table[
    (contingency_table.sum(axis=1) > 10) & (contingency_table.sum(axis=0) > 10)
]

# Calculate chi-square statistic if the filtered table is not empty
if not contingency_table_filtered.empty and contingency_table_filtered.shape == (2,2): # chi2_contingency requires >= 2x2 table
    chi2, p_value, dof, expected = chi2_contingency(contingency_table_filtered)
    result = {
        'chi2_statistic': chi2,
        'p_value': p_value,
        'degrees_of_freedom': dof,
        'expected_frequencies': expected.tolist()
    }
else:
    result = {'message': 'Not enough data to calculate chi-square statistic after filtering (need at least a 2x2 table with marginal totals > 10).'}

print("__RESULT__:")
print(json.dumps(result))"""

